import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import {
  Box,
  Paper,
  Typography,
  TextField,
  Button,
  Grid,
  Divider,
  Alert,
  CircularProgress,
  MenuItem,
  FormControl,
  InputLabel,
  Select,
} from '@mui/material';
import { Save, Cancel, Inventory } from '@mui/icons-material';
import { toast } from 'react-toastify';
import { itemService } from '../../services/itemService';
import { brandService } from '../../services/brandService';
import { groupService } from '../../services/groupService';
import { unitService } from '../../services/unitService';
import { taxService } from '../../services/taxService';

const ItemForm = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const isEdit = Boolean(id);

  const [formData, setFormData] = useState({
    code: '',
    name: '',
    description: '',
    brandId: '',
    groupId: '',
    sectionId: '',
    unitId: '',
    taxId: '',
    purchasePrice: 0,
    sellingPrice: 0,
    gstRate: 0,
    hsnCode: '',
    openingStock: 0,
    currentStock: 0,
    minStockLevel: 0,
    maxStockLevel: 0,
    reorderLevel: 0,
  });
  const [brands, setBrands] = useState([]);
  const [groups, setGroups] = useState([]);
  const [units, setUnits] = useState([]);
  const [taxes, setTaxes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchMasterData();
    if (isEdit) {
      fetchItem();
    }
  }, [id]);

  const fetchMasterData = async () => {
    try {
      const [brandsData, groupsData, unitsData, taxesData] = await Promise.all([
        brandService.getAll(),
        groupService.getAll(),
        unitService.getAll(),
        taxService.getAll(),
      ]);
      setBrands(brandsData);
      setGroups(groupsData);
      setUnits(unitsData);
      setTaxes(taxesData);
    } catch (error) {
      console.error('Failed to fetch master data:', error);
    }
  };

  const fetchItem = async () => {
    try {
      setLoading(true);
      const data = await itemService.getById(id);
      setFormData({
        code: data.code || '',
        name: data.name || '',
        description: data.description || '',
        brandId: data.brandId || '',
        groupId: data.groupId || '',
        sectionId: data.sectionId || '',
        unitId: data.unitId || '',
        taxId: data.taxId || '',
        purchasePrice: data.purchasePrice || 0,
        sellingPrice: data.sellingPrice || 0,
        gstRate: data.gstRate || 0,
        hsnCode: data.hsnCode || '',
        openingStock: data.openingStock || 0,
        currentStock: data.currentStock || 0,
        minStockLevel: data.minStockLevel || 0,
        maxStockLevel: data.maxStockLevel || 0,
        reorderLevel: data.reorderLevel || 0,
      });
    } catch (error) {
      toast.error('Failed to fetch item details');
      navigate('/items');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: ['purchasePrice', 'sellingPrice', 'gstRate', 'openingStock', 'currentStock', 'minStockLevel', 'maxStockLevel', 'reorderLevel'].includes(name)
        ? parseFloat(value) || 0
        : value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (!formData.code || !formData.name) {
      setError('Code and Name are required');
      return;
    }

    try {
      setLoading(true);
      if (isEdit) {
        await itemService.update(id, formData);
        toast.success('Item updated successfully');
      } else {
        await itemService.create(formData);
        toast.success('Item created successfully');
      }
      navigate('/items');
    } catch (error) {
      setError(error.response?.data?.error || 'Failed to save item');
    } finally {
      setLoading(false);
    }
  };

  if (loading && isEdit) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="400px">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box>
      <Box display="flex" alignItems="center" gap={2} mb={3}>
        <Inventory sx={{ fontSize: 40, color: '#1976d2' }} />
        <Box>
          <Typography variant="h4" fontWeight="bold">
            {isEdit ? 'Edit Item' : 'Add New Item'}
          </Typography>
          <Typography variant="body2" color="textSecondary">
            {isEdit ? 'Update item information' : 'Create a new product in the system'}
          </Typography>
        </Box>
      </Box>

      <Paper sx={{ p: 3, borderRadius: 2 }}>
        {error && (
          <Alert severity="error" sx={{ mb: 3 }} onClose={() => setError('')}>
            {error}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          <Typography variant="h6" gutterBottom sx={{ mb: 2 }}>
            Basic Information
          </Typography>
          <Grid container spacing={3}>
            <Grid item xs={12} md={4}>
              <TextField
                fullWidth
                label="Item Code"
                name="code"
                value={formData.code}
                onChange={handleChange}
                required
                placeholder="Enter unique item code"
              />
            </Grid>
            <Grid item xs={12} md={8}>
              <TextField
                fullWidth
                label="Item Name"
                name="name"
                value={formData.name}
                onChange={handleChange}
                required
                placeholder="Enter item name"
              />
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Description"
                name="description"
                value={formData.description}
                onChange={handleChange}
                multiline
                rows={2}
                placeholder="Enter item description"
              />
            </Grid>
          </Grid>

          <Divider sx={{ my: 3 }} />

          <Typography variant="h6" gutterBottom sx={{ mb: 2 }}>
            Classification
          </Typography>
          <Grid container spacing={3}>
            <Grid item xs={12} md={3}>
              <FormControl fullWidth>
                <InputLabel>Brand</InputLabel>
                <Select
                  name="brandId"
                  value={formData.brandId}
                  onChange={handleChange}
                  label="Brand"
                >
                  <MenuItem value="">None</MenuItem>
                  {brands.map((brand) => (
                    <MenuItem key={brand.id} value={brand.id}>
                      {brand.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} md={3}>
              <FormControl fullWidth>
                <InputLabel>Group</InputLabel>
                <Select
                  name="groupId"
                  value={formData.groupId}
                  onChange={handleChange}
                  label="Group"
                >
                  <MenuItem value="">None</MenuItem>
                  {groups.map((group) => (
                    <MenuItem key={group.id} value={group.id}>
                      {group.name}
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} md={3}>
              <FormControl fullWidth>
                <InputLabel>Unit</InputLabel>
                <Select
                  name="unitId"
                  value={formData.unitId}
                  onChange={handleChange}
                  label="Unit"
                >
                  <MenuItem value="">None</MenuItem>
                  {units.map((unit) => (
                    <MenuItem key={unit.id} value={unit.id}>
                      {unit.name} ({unit.shortName})
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={12} md={3}>
              <FormControl fullWidth>
                <InputLabel>Tax</InputLabel>
                <Select
                  name="taxId"
                  value={formData.taxId}
                  onChange={handleChange}
                  label="Tax"
                >
                  <MenuItem value="">None</MenuItem>
                  {taxes.map((tax) => (
                    <MenuItem key={tax.id} value={tax.id}>
                      {tax.name} ({tax.taxPercentage}%)
                    </MenuItem>
                  ))}
                </Select>
              </FormControl>
            </Grid>
          </Grid>

          <Divider sx={{ my: 3 }} />

          <Typography variant="h6" gutterBottom sx={{ mb: 2 }}>
            Pricing & Tax
          </Typography>
          <Grid container spacing={3}>
            <Grid item xs={12} md={3}>
              <TextField
                fullWidth
                label="Purchase Price"
                name="purchasePrice"
                type="number"
                value={formData.purchasePrice}
                onChange={handleChange}
                InputProps={{ startAdornment: '₹' }}
              />
            </Grid>
            <Grid item xs={12} md={3}>
              <TextField
                fullWidth
                label="Selling Price"
                name="sellingPrice"
                type="number"
                value={formData.sellingPrice}
                onChange={handleChange}
                InputProps={{ startAdornment: '₹' }}
              />
            </Grid>
            <Grid item xs={12} md={3}>
              <TextField
                fullWidth
                label="GST Rate (%)"
                name="gstRate"
                type="number"
                value={formData.gstRate}
                onChange={handleChange}
              />
            </Grid>
            <Grid item xs={12} md={3}>
              <TextField
                fullWidth
                label="HSN Code"
                name="hsnCode"
                value={formData.hsnCode}
                onChange={handleChange}
                placeholder="Enter HSN code"
              />
            </Grid>
          </Grid>

          <Divider sx={{ my: 3 }} />

          <Typography variant="h6" gutterBottom sx={{ mb: 2 }}>
            Stock Management
          </Typography>
          <Grid container spacing={3}>
            <Grid item xs={12} md={3}>
              <TextField
                fullWidth
                label="Opening Stock"
                name="openingStock"
                type="number"
                value={formData.openingStock}
                onChange={handleChange}
              />
            </Grid>
            <Grid item xs={12} md={3}>
              <TextField
                fullWidth
                label="Current Stock"
                name="currentStock"
                type="number"
                value={formData.currentStock}
                onChange={handleChange}
              />
            </Grid>
            <Grid item xs={12} md={2}>
              <TextField
                fullWidth
                label="Min Stock Level"
                name="minStockLevel"
                type="number"
                value={formData.minStockLevel}
                onChange={handleChange}
              />
            </Grid>
            <Grid item xs={12} md={2}>
              <TextField
                fullWidth
                label="Max Stock Level"
                name="maxStockLevel"
                type="number"
                value={formData.maxStockLevel}
                onChange={handleChange}
              />
            </Grid>
            <Grid item xs={12} md={2}>
              <TextField
                fullWidth
                label="Reorder Level"
                name="reorderLevel"
                type="number"
                value={formData.reorderLevel}
                onChange={handleChange}
              />
            </Grid>
          </Grid>

          <Divider sx={{ my: 3 }} />

          <Box display="flex" gap={2} justifyContent="flex-end">
            <Button
              variant="outlined"
              startIcon={<Cancel />}
              onClick={() => navigate('/items')}
            >
              Cancel
            </Button>
            <Button
              type="submit"
              variant="contained"
              startIcon={<Save />}
              disabled={loading}
            >
              {loading ? 'Saving...' : isEdit ? 'Update Item' : 'Create Item'}
            </Button>
          </Box>
        </form>
      </Paper>
    </Box>
  );
};

export default ItemForm;
